/* Pico.css provides base styling - only custom additions needed */

main {
  max-width: 52rem;
  margin: 0 auto;
}

.prompt-row {
  display: block;
  padding: 0.75rem 0;
  border-bottom: 1px solid #ddd;
}

.prompt-row .name {
  font-family: ui-monospace, monospace;
  font-weight: bold;
}

.prompt-row textarea {
  width: 100%;
  font-family: ui-monospace, monospace;
  margin: 0.5rem 0;
}

.actions {
  display: flex;
  gap: 0.5rem;
}

.add {
  margin-top: 1.5rem;
  padding-top: 1rem;
  border-top: 1px solid #ccc;
}

.title-row {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  flex-wrap: wrap;
}

.title-input {
  flex: 1;
  min-width: 200px;
}

.error {
  color: #a22;
  margin: 0.5rem 0;
}

.success {
  color: #2a2;
  margin: 0.5rem 0;
}

/* htmx loading indicator */
.htmx-indicator {
  opacity: 0;
  transition: opacity 200ms ease-in;
}

.htmx-request .htmx-indicator {
  opacity: 1;
}

.htmx-request.htmx-indicator {
  opacity: 1;
}

/* Task card styling */
.task-card {
  transition: opacity 0.3s, transform 0.3s;
}

.htmx-swapping .task-card {
  opacity: 0;
  transform: translateX(-20px);
}

/* Title slot: stable container for the title input — swaps only ever replace its
   innerHTML, never the h1 or the buttons beside it. */
.title-slot {
  flex: 1;
  min-width: 200px;
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.title-slot .title-input {
  flex: 1;
  min-width: 0;
}

/* Explore: compact actions table */
.explore-actions {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.85rem;
  margin: 0.75rem 0;
}

.explore-actions th,
.explore-actions td {
  text-align: left;
  vertical-align: top;
  padding: 0.25rem 0.5rem;
  border-bottom: 1px solid #e5e5e5;
}

.explore-actions th {
  color: #666;
  font-weight: 600;
}

.explore-actions td:first-child {
  white-space: nowrap;
  font-family: ui-monospace, monospace;
  color: #555;
}

.explore-actions td:last-child {
  white-space: nowrap;
  text-align: right;
  color: #888;
  font-size: 0.78rem;
}

.explore-actions pre {
  margin: 0;
  white-space: pre-wrap;
  word-break: break-word;
  font-size: 0.8rem;
}

.explore-actions code {
  word-break: break-all;
}

.trunc-marker {
  color: #a80;
}

.explore-meta {
  color: #666;
  margin: 0.25rem 0;
}

.explore-stale {
  background: #fff3cd;
  border: 1px solid #e0c878;
  border-radius: 6px;
  padding: 0.4rem 0.75rem;
  font-size: 0.9rem;
}

.explore-summary {
  border-left: 3px solid #7ab;
  padding-left: 0.75rem;
  margin: 1rem 0;
}

.explore-questions ul {
  margin: 0.25rem 0 0.5rem;
}

/* Plan stage: Q&A form + final plan */
.plan-meta {
  color: #666;
  margin: 0.25rem 0;
}

.plan-questions .plan-question {
  border: 1px solid #e0e0e0;
  border-radius: 6px;
  padding: 0.5rem 0.75rem;
  margin: 0.5rem 0;
}

.plan-questions .plan-question legend {
  font-size: 0.9rem;
  font-weight: 600;
  padding: 0 0.25rem;
}

.plan-options {
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
}

.plan-option {
  display: flex;
  align-items: center;
  gap: 0.4rem;
  margin: 0;
  font-weight: normal;
}

.plan-option input {
  margin: 0;
}

.plan-questions textarea {
  width: 100%;
  font-family: inherit;
}

.plan-draft {
  margin: 0.75rem 0;
}

.plan-final {
  border-left: 3px solid #7ab;
  padding-left: 0.75rem;
  margin: 1rem 0;
}

/* Stage config screen */
.part-row {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  padding: 0.5rem 0;
  border-bottom: 1px solid #e5e5e5;
}

.part-row .part-label {
  flex: 0 0 16rem;
  font-weight: 600;
}

.part-row code {
  color: #888;
  font-size: 0.8rem;
}

.part-row select {
  flex: 1;
  min-width: 0;
  margin: 0;
}

.stage-source {
  max-height: 32rem;
  overflow: auto;
  font-size: 0.78rem;
  background: #f6f6f6;
  border: 1px solid #e5e5e5;
  border-radius: 6px;
  padding: 0.75rem;
  white-space: pre;
}

/* Stage tabs (sticky tab bar on task page) */
.stage-tabs {
  position: sticky;
  top: 0;
  background: var(--pico-background-color, #fff);
  z-index: 5;
  display: flex;
  gap: 0.25rem;
  flex-wrap: wrap;
  padding: 0.5rem 0;
  margin: 1.5rem 0 0.75rem;
  border-bottom: 2px solid #e0e0e0;
}

.stage-tabs .tab {
  background: transparent;
  border: none;
  border-bottom: 2px solid transparent;
  padding: 0.4rem 0.75rem;
  margin: 0;
  cursor: pointer;
  font-size: 0.9rem;
  font-weight: 600;
  transition: border-color 0.15s;
}

.stage-tabs .tab:disabled {
  opacity: 0.45;
  cursor: not-allowed;
}

.stage-tabs .tab.selected {
  border-bottom-color: currentColor;
}

.stage-tabs .tab.tab--running { color: #28be5a; }
.stage-tabs .tab.tab--done { color: #2a7fd4; }
.stage-tabs .tab.tab--idle { color: #888; }
.stage-tabs .tab.tab--disabled { color: #bbb; }
.stage-tabs .tab.tab--error { color: #c44; }

.stage-panel {
  display: none;
  padding: 0.5rem 0 1.5rem;
}

.stage-panel.active {
  display: block;
}

.stage-msg {
  padding: 0.4rem 0;
}

.msg-highlight {
  border: 1px dotted rgba(40, 190, 90, 0.30);
  transition: border-color 0.8s;
  border-radius: 4px;
}

.other-input {
  display: none;
  width: 100%;
  margin-top: 0.25rem;
}

.other-input.show {
  display: block;
}

.approval-controls {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
  margin-top: 1rem;
  padding: 0.75rem;
  border: 1px solid #e0e0e0;
  border-radius: 6px;
}

.approval-controls form {
  margin: 0;
}

.approval-controls textarea {
  width: 100%;
}

.handoff-raw {
  width: 100%;
  font-family: ui-monospace, monospace;
  font-size: 0.8rem;
}

.plan-todo {
  border-left: 3px solid #8b8;
  padding-left: 0.75rem;
  margin: 1rem 0;
}

.qa-round .qa-q {
  margin: 0 0 0.15rem;
}

.qa-round .qa-a {
  margin: 0 0 0.5rem;
  color: #444;
}

.task-glyph {
  font-weight: bold;
}

/**
 * Stage tabs, live tab colors, auto-jump/scroll/highlight, and "Other" toggle.
 */

(function () {
  const lastCount = {};

  function initTabs() {
    const panelsRoot = document.getElementById('stage-panels');
    if (!panelsRoot) return;

    const activeSlug = panelsRoot.getAttribute('data-active');
    document.querySelectorAll('.stage-panel').forEach(function (panel) {
      panel.classList.toggle('active', panel.getAttribute('data-slug') === activeSlug);
    });
    document.querySelectorAll('#stage-tabs .tab').forEach(function (tab) {
      tab.classList.toggle('selected', tab.getAttribute('data-slug') === activeSlug);
    });

    document.getElementById('stage-tabs')?.addEventListener('click', function (evt) {
      const tab = evt.target.closest('.tab');
      if (!tab || tab.disabled) return;
      const slug = tab.getAttribute('data-slug');
      const target = tab.getAttribute('data-target');
      if (!slug || !target) return;

      document.querySelectorAll('.stage-panel').forEach(function (p) {
        p.classList.remove('active');
      });
      document.querySelectorAll('#stage-tabs .tab').forEach(function (t) {
        t.classList.remove('selected');
      });

      const panel = document.querySelector(target);
      if (panel) panel.classList.add('active');
      tab.classList.add('selected');
    });
  }

  function refreshTabColors() {
    document.querySelectorAll('[data-stage-status]').forEach(function (wrapper) {
      const slug = wrapper.getAttribute('data-stage-slug');
      const status = wrapper.getAttribute('data-stage-status');
      if (!slug) return;
      const tab = document.querySelector('#stage-tabs .tab[data-slug="' + slug + '"]');
      if (!tab) return;
      tab.classList.remove('tab--running', 'tab--done', 'tab--idle', 'tab--disabled', 'tab--error');
      const cls = {
        running: 'tab--running',
        awaiting: 'tab--running',
        done: 'tab--done',
        idle: 'tab--idle',
        disabled: 'tab--disabled',
        error: 'tab--error',
      }[status] || 'tab--idle';
      tab.classList.add(cls);
    });
  }

  function onAfterSwap(evt) {
    const editor = evt.target.querySelector?.('textarea[name="content"]:not([readonly])');
    if (editor) editor.focus();

    refreshTabColors();

    const wrapper = evt.target.closest?.('[data-stage-status]') ||
      (evt.target.matches?.('[data-stage-status]') ? evt.target : null);
    if (!wrapper) return;

    const panel = wrapper.closest('.stage-panel');
    if (!panel) return;

    const slug = wrapper.getAttribute('data-stage-slug');
    const status = wrapper.getAttribute('data-stage-status');
    const count = parseInt(wrapper.getAttribute('data-msg-count') || '0', 10);
    const prev = lastCount[slug] || 0;
    lastCount[slug] = count;

    if ((status === 'running' || status === 'awaiting') && count > prev) {
      const isActive = panel.classList.contains('active');
      if (!isActive && slug) {
        const tab = document.querySelector('#stage-tabs .tab[data-slug="' + slug + '"]');
        if (tab && !tab.disabled) tab.click();
      }
      const msgs = wrapper.querySelectorAll('.stage-msg');
      const last = msgs[msgs.length - 1];
      if (last) {
        last.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
        last.classList.add('msg-highlight');
        setTimeout(function () {
          last.classList.remove('msg-highlight');
        }, 2000);
      }
    }

    if (status === 'done' && slug === 'plan_review') {
      const implTab = document.querySelector('#stage-tabs .tab[data-slug="implementation"]');
      if (implTab) {
        implTab.disabled = false;
        implTab.classList.remove('tab--disabled');
        implTab.click();
      }
    }
  }

  function initOtherToggle() {
    document.body.addEventListener('change', function (evt) {
      const input = evt.target;
      if (!input.matches('input[type="radio"], input[type="checkbox"]')) return;
      const fieldset = input.closest('.plan-question');
      if (!fieldset) return;

      const name = input.name;
      const otherTa = fieldset.querySelector('textarea[name="' + name + '__other"]');
      if (!otherTa) return;

      if (input.type === 'radio') {
        const isOther = input.value === '__other__' && input.checked;
        otherTa.disabled = !isOther;
        otherTa.classList.toggle('show', isOther);
        if (!isOther && !fieldset.querySelector('input[value="__other__"]:checked')) {
          otherTa.classList.remove('show');
        }
      } else if (input.type === 'checkbox' && input.value === '__other__') {
        otherTa.disabled = !input.checked;
        otherTa.classList.toggle('show', input.checked);
      }
    });
  }

  function seedCounts() {
    document.querySelectorAll('[data-stage-slug][data-msg-count]').forEach(function (w) {
      lastCount[w.getAttribute('data-stage-slug')] =
        parseInt(w.getAttribute('data-msg-count') || '0', 10);
    });
  }

  document.addEventListener('DOMContentLoaded', function () {
    initTabs();
    seedCounts();
    refreshTabColors();
    initOtherToggle();
  });

  document.body.addEventListener('htmx:afterSwap', onAfterSwap);

  document.body.addEventListener('htmx:responseError', function (evt) {
    console.error('htmx error:', evt.detail);
  });
})();
